(function(){
  var SKELETON_IMG = "data:image/jpeg;base64,";

  var QUESTIONS = [
    { num: 1,  correct: "Skull (Cranium)",         fact: "Your skull is like a helmet — it protects your brain!" },
    { num: 2,  correct: "Collarbone (Clavicle)",   fact: "Your collarbone goes across the top of your chest, like a little hanger for your arms." },
    { num: 3,  correct: "Upper arm bone (Humerus)",fact: "The upper arm bone is the biggest bone between your shoulder and your elbow." },
    { num: 4,  correct: "Forearm bone (Ulna)",     fact: "The ulna is the forearm bone that lines up with your pinky finger." },
    { num: 5,  correct: "Forearm bone (Radius)",   fact: "The radius is the forearm bone that lines up with your thumb — it lets your palm turn up and down!" },
    { num: 6,  correct: "Thigh bone (Femur)",      fact: "The thigh bone is the longest, strongest bone in your whole body!" },
    { num: 7,  correct: "Shin bone (Tibia)",       fact: "The shin bone is the big bone in the front of your lower leg." },
    { num: 8,  correct: "Jawbone (Mandible)",      fact: "Your jawbone is the only bone in your head that can move — it helps you chew and talk!" },
    { num: 9,  correct: "Breastbone (Sternum)",    fact: "The breastbone is a flat bone in the middle of your chest — your ribs connect to it." },
    { num: 10, correct: "Ribs",                    fact: "Your ribs curve around your chest to protect your heart and lungs." },
    { num: 11, correct: "Hip bone (Ilium)",        fact: "The ilium is the wide, curvy part of your hip bone — you can feel it if you put your hands on your hips!" },
    { num: 12, correct: "Tailbone (Sacrum)",       fact: "At the very bottom of your spine is a bone that helps connect your backbone to your hips." },
    { num: 13, correct: "Hip bone (Pubis)",        fact: "The pubis is the front part of your hip bone, where the left and right sides of your pelvis meet." },
    { num: 14, correct: "Kneecap (Patella)",       fact: "Your kneecap is the small round bone that protects the front of your knee." },
    { num: 15, correct: "Calf bone (Fibula)",      fact: "The fibula is the thinner bone next to your shin bone, running down the outside of your lower leg." },
    { num: 16, correct: "Foot bones",              fact: "Each foot has 26 tiny bones working together to help you balance, walk, and run!" },
    { num: 17, correct: "Backbone (Spine)",        fact: "Your backbone is a stack of small bones called vertebrae — they protect your spinal cord and let you bend and twist." }
  ];

  var ROUND_SIZE = 8;
  var ALL_NAMES = QUESTIONS.map(function(q){ return q.correct; });

  function shuffle(arr){
    var a = arr.slice();
    for (var i = a.length - 1; i > 0; i--){
      var j = Math.floor(Math.random() * (i + 1));
      var t = a[i]; a[i] = a[j]; a[j] = t;
    }
    return a;
  }

  function pickChoices(correct){
    var others = shuffle(ALL_NAMES.filter(function(n){ return n !== correct; })).slice(0, 3);
    return shuffle(others.concat([correct]));
  }

  function newRound(){
    return shuffle(QUESTIONS.map(function(q, i){ return i; })).slice(0, ROUND_SIZE);
  }

  function start(host, ctx){
    var order = newRound();
    var idx = 0;
    var correctFirstTry = 0;

    function render(){
      if (idx >= order.length){
        renderSummary();
        return;
      }
      var q = QUESTIONS[order[idx]];
      var choices = pickChoices(q.correct);

      host.innerHTML =
        '<div class="center">' +
          '<div class="h2">Clover\'s X-ray Check-Up</div>' +
          '<div class="sub">Clover twisted an ankle at soccer practice! Dr. Patel needs your help ' +
          'reading the X-ray so Clover gets the right care. Can you name the bones?</div>' +
        '</div>' +
        '<div class="row center mt">' +
          '<img src="' + SKELETON_IMG + '" alt="Labeled skeleton" style="max-width:260px;width:100%;border-radius:12px;" />' +
        '</div>' +
        '<div class="center mt">' +
          '<div class="sub">Question ' + (idx + 1) + ' of ' + order.length + '</div>' +
          '<div class="h3">Look at the skeleton picture above. Which bone is number ' + q.num + '?</div>' +
        '</div>' +
        '<div class="story-grid mt" id="choices">' +
          choices.map(function(c){
            return '<button class="q-opt" data-answer="' + c.replace(/"/g,'&quot;') + '">' + c + '</button>';
          }).join('') +
        '</div>' +
        '<div class="fb center mt" id="fb" style="min-height:1.5em;"></div>';

      var btns = host.querySelectorAll('#choices .q-opt');
      btns.forEach(function(btn){
        btn.addEventListener('pointerup', function(){
          handleAnswer(btn, q, btns);
        });
      });
    }

    function handleAnswer(btn, q, allBtns){
      var chosen = btn.getAttribute('data-answer');
      var fb = host.querySelector('#fb');
      if (chosen === q.correct){
        btn.classList.add('correct');
        allBtns.forEach(function(b){ b.disabled = true; });
        if (!btn.dataset.wrongTried){
          correctFirstTry++;
        }
        fb.className = 'fb ok center mt';
        fb.innerHTML = 'That\'s right! Number ' + q.num + ' is the ' + q.correct.toLowerCase() + '. ' + q.fact;
        if (ctx.toast) ctx.toast('Nice job!');
        var nextBtn = document.createElement('button');
        nextBtn.className = 'btn teal mt';
        nextBtn.textContent = (idx + 1 < order.length) ? 'Next →' : 'See Results →';
        nextBtn.addEventListener('pointerup', function(){
          idx++;
          render();
        });
        fb.appendChild(document.createElement('br'));
        fb.appendChild(nextBtn);
      } else {
        btn.disabled = true;
        btn.dataset.wrongTried = '1';
        fb.className = 'fb no center mt';
        fb.textContent = 'Not quite — try another one!';
      }
    }

    function renderSummary(){
      var star = correctFirstTry >= 6;
      var coins = correctFirstTry;
      if (!ctx.state.hospitalDone){
        ctx.state.hospitalDone = true;
        ctx.award({ coins: coins, star: star });
        if (ctx.confetti && star) ctx.confetti();
      }

      var cloverImg = star ? ctx.clover.cele : ctx.clover.head;
      var msg = star
        ? 'Clover is all better thanks to you! Dr. Patel says you\'d make a great doctor.'
        : 'Clover feels much better already! Come back and visit the hospital again anytime.';

      host.innerHTML =
        '<div class="center">' +
          '<img src="' + cloverImg + '" alt="Clover" style="width:120px;" />' +
          '<div class="h2 mt">' + correctFirstTry + ' / ' + order.length + ' bones named correctly!</div>' +
          '<div class="sub mt">' + msg + '</div>' +
          (star ? '<div class="sub mt">⭐ You earned a star!</div>' : '') +
          '<div class="row center mt">' +
            '<button class="btn green" id="again">Play Again</button>' +
            '<button class="btn ghost" id="done">← Map</button>' +
          '</div>' +
        '</div>';

      host.querySelector('#again').addEventListener('pointerup', function(){
        order = newRound();
        idx = 0;
        correctFirstTry = 0;
        render();
      });
      host.querySelector('#done').addEventListener('pointerup', function(){
        ctx.close();
      });
    }

    render();
  }

  window.Stops.register('5A', { name: 'Hospital', start: start });
})();
